    min_time_to_node = float('inf')

    for i, customer in enumerate(unvisited_customers):
        dist_to_node = np.linalg.norm(cur_truck_pos - customer)
        travel_time = dist_to_node / truck_speed

        if current_time + travel_time <= time_windows[i][1]:
            wait_time = max(0, time_windows[i][0] - (current_time + travel_time))
            total_time_to_node = current_time + travel_time + wait_time
            if total_time_to_node < min_time_to_node:
                min_time_to_node = total_time_to_node
                best_node = i

    if best_node == -1:
        for i, customer in enumerate(unvisited_customers):
